def wordBreak(s, wordDict):
    wordSet = set(wordDict); memo = {}
    def dfs(s):
        if s in memo: return memo[s]
        if not s: return [""]
        res = []
        for w in wordSet:
            if s.startswith(w):
                for sub in dfs(s[len(w):]):
                    res.append((w + " " + sub).strip())
        memo[s] = res; return res
    return dfs(s)

